Based on my thorough exploration of the playwright test mocking pattern in the public-pages app, here's the complete breakdown:

## Playwright Test Mocking Pattern - Server-to-Server API Requests

### Overview

The public-pages app uses a **request-mocking-protocol** pattern that intercepts HTTP requests at the server level (Node.js/Nitro) and returns mocked responses. This is a **declarative, wire-protocol-based approach** rather than traditional test doubles. Mocks are defined by Playwright tests and transmitted to the server via HTTP headers.

---

## 1. How Server-to-Server API Requests Are Mocked

### Architecture

The system uses three key components:

1. **MockClient** (in Playwright tests) - Defines mocks on the browser/test side
2. **HTTP Headers** - Transports mock definitions from browser to server via `x-mock-request` header
3. **MSW + request-mocking-protocol handler** (on server) - Intercepts requests and applies mocks
4. **getRequestHeaders()** - The server reads the incoming request headers to extract mocks

### Flow Diagram

```
Playwright Test
    ↓
MockClient.PUT(url, response) → Creates mock schema
    ↓
context.setExtraHTTPHeaders(headers) → Sets x-mock-request header
    ↓
HTTP Request to Server (with x-mock-request header)
    ↓
MSW Handler (createHandler) reads headers
    ↓
extractMockSchemas(getRequestHeaders()) → Parses header
    ↓
Routes request through mock if matches, otherwise normal handling
```

---

## 2. Example Test Files

### **/Users/duhl/git/ui/apps/public-pages/tests/integration/lead.spec.ts**

Complete example showing server-to-server API mocking:

```typescript
import { expect, type Page } from "@playwright/test";
import { MockClient } from "request-mocking-protocol";
import { test as base } from "./test-fixture";

// Create extended test fixture with mockServerRequest
export const test = base.extend<{ mockServerRequest: MockClient }>({
  mockServerRequest: async ({ context }, use) => {
    const mockClient = new MockClient();
    // onChange callback: when mocks are added, update browser headers
    mockClient.onChange = async (headers) =>
      context.setExtraHTTPHeaders(headers);
    await use(mockClient);
  },
});

// Mock patterns for URL matching
const actionPageUrlPattern =
  /https?:\/\/[^/]+\/public\/v3\/action_pages\/[^/?]+/;
const leadSubmissionUrlPattern =
  /https?:\/\/[^/]+\/public\/v3\/submissions\/lead\/?(?:\?.*)?$/;

// Define mock response shapes
const mockActionPage = {
  id: "ap_123",
  headerTitleText: "Join the Movement",
  description: "Help us build momentum with a quick sign-up.",
  account: {
    id: "acct_123",
    displayName: "Demo Org",
    allowCustomCss: false,
    slug: "demo-org",
  },
};

// Helper to register a mock
async function mockPublicActionPage(mockServerRequest: MockClient) {
  await mockServerRequest.GET(actionPageUrlPattern, { body: mockActionPage });
}

async function mockLeadSubmission(
  mockServerRequest: MockClient,
  body: Record<string, unknown> = {},
) {
  await mockServerRequest.PUT(leadSubmissionUrlPattern, {
    body: {
      id: "lead_123",
      actionPage: {
        id: "ap_123",
        name: "Join the Movement",
        pageType: "lead",
      },
      addressAttributes: {
        city: "Austin",
        country: "US",
        line1: "123 Main St",
        postalCode: "78701",
        region: "TX",
      },
      callbackUrl: null,
      ...body,
    },
  });
}

// Example test using mocks
test("shows the heading", async ({ page, mockServerRequest }) => {
  // Register mock BEFORE navigation
  await mockPublicActionPage(mockServerRequest);

  // Navigate - server will use the mock instead of real API
  await page.goto("/lead/demo-org/lead-token", { waitUntil: "domcontentloaded" });

  // Assert UI rendered with mocked data
  await expect(
    page.getByRole("heading", { name: "Join the Movement" }),
  ).toBeVisible();
});

// Example with request body matching
test("submits email and phone opt-in values in payload", async ({
  page,
  mockServerRequest,
}) => {
  await mockPublicActionPage(mockServerRequest);

  // Mock that MATCHES on request body
  await mockServerRequest.PUT(
    {
      url: leadSubmissionUrlPattern,
      body: {
        emailOptIn: true,
        phoneOptIn: true,
        communicationsConsentEmail: true,
        communicationsConsentPhone: true,
      },
    },
    {
      body: {
        id: "lead_123",
        callbackUrl: "/thanks",
      },
    },
  );

  await page.goto("/lead/demo-org/lead-token");
  // Fill form and submit
  await page.getByLabel("Email", { exact: true }).fill("test@example.com");
  // ... more form fills
  await page.getByRole("button", { name: "Submit" }).click();

  // Will receive mocked response
  await expect(page).toHaveURL(new RegExp(`/thanks$`));
});
```

### **/Users/duhl/git/ui/apps/public-pages/tests/integration/test-fixture.ts**

Base fixture that blocks external requests:

```typescript
import { test as base } from "@playwright/test";

export const test = base.extend({
  page: async ({ page, baseURL, context }, use) => {
    const localOrigin = baseURL ? new URL(baseURL).origin : undefined;
    const isSpecialScheme = (url: string) =>
      url.startsWith("about:") ||
      url.startsWith("blob:") ||
      url.startsWith("data:");

    // Block all external requests EXCEPT those to the local server
    await context.route("**/*", async (route) => {
      const requestUrl = route.request().url();
      if (!localOrigin || isSpecialScheme(requestUrl)) {
        await route.continue();
        return;
      }

      const requestOrigin = new URL(requestUrl).origin;
      if (requestOrigin === localOrigin) {
        // Allow local requests (will be handled by MSW mocking)
        await route.continue();
        return;
      }

      // Block external requests
      await route.abort();
      throw new Error(
        `[Playwright] Blocked external browser request: ${route.request().method()} ${requestUrl}\n All requests to external APIs must flow through server functions`,
      );
    });

    await use(page);
    await context.unroute("**/*");
  },
});

export { expect } from "@playwright/test";
```

