## 4. Mock Server Setup & Fixtures

### **/Users/duhl/git/ui/apps/public-pages/src/mocks/request-mocking.ts**

**Server-side MSW setup:**

```typescript
import { getRequestHeaders } from "@tanstack/start-server-core";
import { setupServer } from "msw/node";
import { createHandler } from "request-mocking-protocol/msw";

export function setupRequestMocking() {
  // Create MSW handler using the request-mocking-protocol
  const mockHandler = createHandler(() => {
    // Critical: Read incoming request headers to extract mock definitions
    // This is how mocks from Playwright tests get to the server
    return getRequestHeaders();
  });

  // Initialize MSW server with the mock handler
  const mswServer = setupServer(
    mockHandler as unknown as Parameters<typeof setupServer>[0],
  );

  // Start MSW with error handling for unhandled requests
  mswServer.listen({
    onUnhandledRequest(request) {
      console.error(
        `[MSW] Unhandled request: ${request.method} ${request.url}`,
      );
      throw new Error(
        `[MSW] Unhandled request: ${request.method} ${request.url}`,
      );
    },
  });
}
```

**Initialization in router:**

```typescript
// /Users/duhl/git/ui/apps/public-pages/src/router.tsx
const enableRequestMocking = import.meta.env.VITE_ENABLE_RMP === "true";

if (enableRequestMocking && import.meta.env.SSR) {
  const { setupRequestMocking } = await import("./mocks/request-mocking");
  setupRequestMocking();
}
```

### **/Users/duhl/git/ui/apps/public-pages/src/mocks/browser.ts**

Browser-side MSW setup (not used in these tests, but available):

```typescript
import { setupWorker } from "msw/browser";

declare global {
  interface Window {
    __publicPagesMswWorker?: ReturnType<typeof setupWorker>;
  }
}

export async function startBrowserRequestGuard(
  options: BrowserRequestGuardOptions = {},
) {
  if (window.__publicPagesMswWorker) {
    return;
  }

  const worker = setupWorker();
  const allowedOrigins = new Set([
    window.location.origin,
    ...(options.allowedOrigins ?? []),
  ]);

  await worker.start({
    quiet: true,
    onUnhandledRequest({ method, url }) {
      const requestOrigin = toOrigin(url);
      if (allowedOrigins.has(requestOrigin)) {
        return;
      }

      throw new Error(
        `[MSW] Blocked external browser request: ${method} ${url}\n All requests to external APIs must flow through server functions`,
      );
    },
  });

  window.__publicPagesMswWorker = worker;
}
```

