import { createServerOnlyFn } from "@tanstack/react-start";
import { getRequestUrl } from "@tanstack/react-start/server";

function normalizeAbsoluteUrl(url: string) {
  if (url.startsWith("http://") || url.startsWith("https://")) {
    return url;
  }

  return `http://${url}`;
}

function getRequiredSessionSecret() {
  const sessionSecret = process.env.SESSION_SECRET;

  if (!sessionSecret) {
    throw new Error("SESSION_SECRET is required for org-next auth sessions.");
  }

  return sessionSecret;
}

function getAuthAppUrl() {
  // todo: switch to portless? (https://port1355.dev/)
  return process.env.VITE_AUTH_APP_URL || "http://localhost:3208";
}

const getRequestOrigin = createServerOnlyFn(() => {
  return getRequestUrl({
    xForwardedHost: true,
    xForwardedProto: true,
  }).origin;
});

export const getServerOrgApiBaseUrl = createServerOnlyFn(() => {
  const apiHostname = process.env.VITE_API_HOSTNAME;

  if (apiHostname) {
    return normalizeAbsoluteUrl(apiHostname);
  }

  return getRequestOrigin();
});

export const getServerSessionSecret = createServerOnlyFn(() => {
  return getRequiredSessionSecret();
});

export const getServerAuthConfig = createServerOnlyFn(() => {
  const origin = getRequestOrigin();

  return {
    authAppUrl: getAuthAppUrl(),
    clientId: process.env.VITE_AUTH_CLIENT_ID || "local-client",
    cognitoTokenEndpoint: process.env.VITE_COGNITO_TOKEN_ENDPOINT || "",
    logoutUri: `${origin}/login`,
    redirectUri: `${origin}/oauth/callback`,
    scope: "openid email profile",
  };
});

