import path from "node:path";
import { fileURLToPath } from "node:url";
import { defineConfig, devices } from "@playwright/test";
import dotenv from "dotenv";

const configDirectory = path.dirname(fileURLToPath(import.meta.url));
/** Resolved from the config file so discovery works when CWD is the repo root (e.g. VS Code, `playwright --config apps/org-next/...`). */
const testsRoot = path.join(configDirectory, "tests");
const testEnvPath = path.resolve(configDirectory, ".env.test");
dotenv.config({ path: testEnvPath, override: true });

const ciBaseUrl = "http://localhost:3210";
const localBaseUrl = "http://localhost:3210";
const baseUrl = process.env.CI ? ciBaseUrl : localBaseUrl;
const readinessUrl = `${baseUrl}/robots.txt`;
const webServerEnv = Object.fromEntries(
  Object.entries(process.env).filter(
    (entry): entry is [string, string] => entry[1] !== undefined,
  ),
);

/**
 * See https://playwright.dev/docs/test-configuration.
 */
export default defineConfig({
  timeout: process.env.CI ? 20_000 : 5_000,
  testDir: testsRoot,
  fullyParallel: true,
  retries: 0,
  workers: process.env.CI ? 8 : 5,
  reporter: [
    ["html", { outputFolder: path.join(configDirectory, "playwright-report") }],
  ],
  expect: {
    timeout: process.env.CI ? 10_000 : 5_000,
  },
  use: {
    baseURL: baseUrl,
    trace: "off",
    video: "retain-on-failure",
  },
  projects: [{ name: "chromium", use: { ...devices["Desktop Chrome"] } }],
  webServer: {
    command: process.env.CI
      ? "pnpm exec vite build --mode test && pnpm exec vite preview --port 3210"
      : "pnpm exec vite dev --port 3210 --mode test",
    env: webServerEnv,
    url: readinessUrl,
    reuseExistingServer: !process.env.CI,
    stdout: "pipe",
    stderr: "pipe",
  },
});

