import { AppHeader } from "@/components/app-header";
import {
  createFileRoute,
  getRouteApi,
  Link,
  redirect,
} from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { Badge, Button, Card, Progress } from "@workspace/ui";
import {
  ArrowRight,
  Check,
  ChevronRight,
  Copy,
  Plus,
  Settings,
  Target,
} from "lucide-react";

// Get the parent data
const authedRouteApi = getRouteApi("/_authed");

const getDashboardPageDataFn = createServerFn({ method: "GET" }).handler(
  async () => {
    const { getDashboardPageData } = await import("../../server/dashboard.ts");
    const { OrgApiError } = await import("../../server/error.ts");

    try {
      const data = await getDashboardPageData();

      if (!data) {
        throw redirect({ to: "/login" });
      }

      return data;
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      throw error;
    }
  },
);

export const Route = createFileRoute("/_authed/")({
  loader: () => getDashboardPageDataFn(),
  component: HomePage,
});

// Quick stat card component
function QuickCard({
  title,
  isEmpty,
  emptyText,
  count,
  subtitle,
}: {
  title: string;
  isEmpty: boolean;
  emptyText: string;
  count: string | number;
  subtitle: string;
}) {
  return (
    <Card className="min-w-40 flex-1 cursor-pointer p-5 transition-all hover:border-foreground/20">
      <div className="font-semibold text-muted-foreground text-xs uppercase tracking-wide">
        {title}
      </div>
      {isEmpty ? (
        <>
          <div className="mt-1.5 font-bold text-3xl text-muted-foreground/50">
            —
          </div>
          <div className="mt-0.5 text-muted-foreground text-sm">
            {emptyText}
          </div>
        </>
      ) : (
        <>
          <div className="mt-1.5 font-bold text-3xl text-foreground">
            {count}
          </div>
          <div className="mt-0.5 text-muted-foreground text-sm">{subtitle}</div>
        </>
      )}
    </Card>
  );
}

// Status configuration for onboarding steps
const statusConfig = {
  not_started: {
    label: "Not started",
    color: "bg-accent text-muted-foreground",
  },
  in_progress: {
    label: "In progress",
    color: "bg-chart-4/15 text-chart-4",
  },
  under_review: {
    label: "Under review",
    color: "bg-chart-3/15 text-chart-3",
  },
  approved: { label: "Complete", color: "bg-chart-2/10 text-chart-2" },
} as const;

type StepStatus = keyof typeof statusConfig;

type OnboardingStep = {
  title: string;
  description?: string;
  action?: string;
  status?: StepStatus;
  blockedMessage?: string;
  showUrl?: boolean;
};

// Sample data
const sampleData = {
  steps: [
    {
      title: "Complete verification",
      description:
        "Submit your organization's documents so you can collect donations and receive payouts. This usually takes 1-2 business days.",
      action: "Start verification",
      status: "not_started" as StepStatus,
    },
    {
      title: "Create your first campaign",
      description:
        "Campaigns help you organize fundraising efforts and track progress toward a goal.",
      action: "Create campaign",
    },
    {
      title: "Create a donation form",
      description: "Build a donation page you can share with supporters.",
      blockedMessage: "Requires a campaign first",
    },
    {
      title: "Share your donation form",
      description:
        "Once your form is ready and verification is complete, you'll get a link to share.",
      blockedMessage: "Available after verification is approved",
    },
  ] as OnboardingStep[],
  activeStep: 0,
  completedSteps: [] as number[],
  campaigns: [] as Array<{
    name: string;
    raised: number;
    goal: number;
    forms: number;
    status: string;
  }>,
  cards: { campaigns: 0, transactions: 0, payouts: 0 },
};

function HomePage() {
  const { user } = authedRouteApi.useLoaderData();
  const data = Route.useLoaderData();

  const greeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "morning";
    if (hour < 17) return "afternoon";
    return "evening";
  };

  const allComplete = sampleData.completedSteps.length === 4;
  const greetingName = user.email ?? "Bob@gmail.com";

  return (
    <div className="min-h-screen bg-muted font-outfit">
      <AppHeader />
      {/* Main Content */}
      <main className="mx-auto max-w-6xl px-6 py-6">
        <div className="mb-6 flex items-center justify-between">
          <h1 className="font-bold text-3xl text-foreground">
            Good {greeting()}, {greetingName}
          </h1>
          <Button
            variant="ghost"
            size="sm"
            className="gap-1.5 text-muted-foreground"
          >
            <Settings className="h-4 w-4" />
            Organization Settings
            <ChevronRight className="h-3.5 w-3.5" />
          </Button>
        </div>

        {/* Quick Access Cards */}
        <div className="mb-6 flex gap-3">
          <QuickCard
            title="Campaigns"
            isEmpty={data.cards.campaigns === 0}
            emptyText="No campaigns yet"
            count={data.cards.campaigns}
            subtitle="active campaign"
          />
          <QuickCard
            title="Transactions"
            isEmpty={data.cards.transactions === 0}
            emptyText="Donations will appear here"
            count={data.cards.transactions}
            subtitle="donations received"
          />
          <QuickCard
            title="Balance"
            isEmpty={data.cards.payouts === 0}
            emptyText="Your balance will show here"
            count={`$${data.cards.payouts.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`}
            subtitle={data.cards.payouts === 0 ? "" : "available"}
          />
        </div>

        {/* Onboarding Steps */}
        {!allComplete && (
          <Card className="mb-8 overflow-hidden">
            <div className="border-border border-b p-6">
              <h2 className="font-bold text-foreground text-xl">
                Welcome to Anedot
              </h2>
              <p className="mt-1 text-muted-foreground text-sm">
                Let's get you set up to start collecting donations. Complete
                these steps in any order.
              </p>
            </div>
            <div className="divide-y divide-border">
              {sampleData.steps.map((step, i) => {
                const isActive = i === sampleData.activeStep;
                const isComplete = sampleData.completedSteps.includes(i);
                return (
                  <div
                    key={step.title}
                    className={`cursor-pointer p-5 transition-colors ${
                      isActive ? "bg-secondary-50/50" : "hover:bg-muted"
                    } ${isComplete ? "py-3" : ""}`}
                  >
                    <div className="flex items-start gap-3.5">
                      <div
                        className={`flex h-7 w-7 shrink-0 items-center justify-center rounded-full font-semibold text-sm ${
                          isComplete
                            ? "bg-chart-2 text-primary-foreground"
                            : isActive
                              ? "bg-secondary-600 text-white"
                              : "bg-accent text-muted-foreground"
                        }`}
                      >
                        {isComplete ? <Check className="h-4 w-4" /> : i + 1}
                      </div>
                      <div className="min-w-0 flex-1">
                        <div className="flex items-center justify-between gap-3">
                          <h3
                            className={`font-semibold text-foreground ${
                              isComplete ? "text-sm" : "text-base"
                            }`}
                          >
                            {step.title}
                          </h3>
                          {step.status && !isComplete && (
                            <Badge
                              className={statusConfig[step.status].color}
                              variant="secondary"
                            >
                              {statusConfig[step.status].label}
                            </Badge>
                          )}
                          {isComplete && (
                            <span className="font-medium text-chart-2 text-sm">
                              Complete
                            </span>
                          )}
                        </div>
                        {!isComplete && step.description && (
                          <p className="mt-1 text-muted-foreground text-sm">
                            {step.description}
                          </p>
                        )}
                        {step.action && !isComplete && (
                          <Button
                            asChild
                            className="mt-3"
                            size="sm"
                            variant={isActive ? "default" : "outline"}
                          >
                            <Link to="/campaigns/new">
                              {step.action}
                              <ArrowRight className="h-4 w-4" />
                            </Link>
                          </Button>
                        )}
                        {step.showUrl && (
                          <div className="mt-3 flex items-center gap-2.5 rounded-lg border border-border bg-muted p-2.5">
                            <code className="flex-1 truncate text-primary text-sm">
                              donate.example.com/spring-gala
                            </code>
                            <Button size="xs" variant="outline">
                              <Copy className="h-3.5 w-3.5" />
                              Copy
                            </Button>
                          </div>
                        )}
                        {step.blockedMessage && !isComplete && (
                          <p className="mt-2 inline-block rounded-md bg-chart-4/15 px-2.5 py-1.5 text-chart-4 text-sm">
                            {step.blockedMessage}
                          </p>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </Card>
        )}

        {/* Active Campaigns Section */}
        <div className="mb-8">
          <div className="mb-3 flex items-center justify-between">
            <h2 className="font-bold text-foreground text-lg">
              Active Campaigns
            </h2>
            <Button
              asChild
              size="sm"
              variant="ghost"
              className="text-secondary-600"
            >
              <Link to="/campaigns/new">
                <Plus className="h-4 w-4" />
                New campaign
              </Link>
            </Button>
          </div>

          {data.campaigns.length === 0 ? (
            <Card className="border-2 border-dashed p-10 text-center">
              <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-xl bg-accent text-primary">
                <Target className="h-6 w-6" />
              </div>
              <p className="font-semibold text-foreground">No campaigns yet</p>
              <p className="mx-auto mt-1.5 max-w-xs text-muted-foreground text-sm">
                Campaigns help you organize fundraising efforts and track
                progress toward a goal.
              </p>
              <Button asChild className="mt-4">
                <Link to="/campaigns/new">
                  <Plus className="h-4 w-4" />
                  Create your first campaign
                </Link>
              </Button>
            </Card>
          ) : (
            <div className="flex flex-col gap-2">
              {data.campaigns.map((c) => {
                const pct = c.goal ? Math.round((c.raised / c.goal) * 100) : 0;
                return (
                  <Link
                    key={c.id}
                    to="/campaigns/$campaignId"
                    params={{ campaignId: c.id.toString() }}
                  >
                    <Card className="flex cursor-pointer items-center gap-4 p-4 transition-colors hover:border-foreground/20">
                      <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-accent text-primary">
                        <Target className="h-5 w-5" />
                      </div>
                      <div className="min-w-0 flex-1">
                        <div className="mb-1 flex items-center gap-2">
                          <span className="font-semibold text-foreground">
                            {c.name}
                          </span>
                          <Badge
                            className={
                              c.status === "live"
                                ? "bg-chart-2/10 text-chart-2"
                                : "bg-chart-4/15 text-chart-4"
                            }
                            variant="secondary"
                          >
                            {c.status}
                          </Badge>
                        </div>
                        {c.goal > 0 && (
                          <div className="flex items-center gap-2.5">
                            <Progress
                              className="h-1.5 flex-1"
                              value={Math.min(pct, 100)}
                            />
                            <span className="shrink-0 font-semibold text-muted-foreground text-xs">
                              ${c.raised.toLocaleString()} / $
                              {c.goal.toLocaleString()}
                            </span>
                          </div>
                        )}
                        <div className="mt-1 text-muted-foreground text-xs">
                          {c.forms} {c.forms === 1 ? "form" : "forms"}
                        </div>
                      </div>
                      <ChevronRight className="h-5 w-5 shrink-0 text-muted-foreground/50" />
                    </Card>
                  </Link>
                );
              })}
            </div>
          )}
        </div>
      </main>
    </div>
  );
