import { createFileRoute, redirect } from "@tanstack/react-router";

/**
 * Intentionally throws in Vite `test` mode so Playwright can assert the root
 * `errorComponent`. In other modes, redirects to home so the URL is harmless.
 */
export const Route = createFileRoute("/playwright-root-error")({
  loader: () => {
    if (import.meta.env.MODE !== "test") {
      throw redirect({ to: "/" });
    }
    throw new Error("E2E probe: root error boundary");
  },
  component: PlaywrightRootErrorProbe,
});

function PlaywrightRootErrorProbe() {
  return null;
}

