export type DashboardCampaign = {
  forms: number;
  goal: number;
  id: number;
  name: string;
  raised: number;
  status: "draft" | "live";
};

export type DashboardPageData = {
  campaigns: DashboardCampaign[];
  cards: {
    campaigns: number;
    payouts: number;
    transactions: number;
  };
};

export async function getDashboardPageData(): Promise<DashboardPageData | null> {
  return {
    campaigns: [
      {
        forms: 4,
        goal: 25000,
        id: 101,
        name: "Spring Membership Drive",
        raised: 18420,
        status: "live",
      },
      {
        forms: 2,
        goal: 10000,
        id: 102,
        name: "Neighborhood Yard Signs",
        raised: 6125,
        status: "live",
      },
      {
        forms: 1,
        goal: 5000,
        id: 103,
        name: "Volunteer Kickoff",
        raised: 0,
        status: "draft",
      },
    ],
    cards: {
      campaigns: 3,
      payouts: 7,
      transactions: 428,
    },
  };
}

