import { setupWorker } from "msw/browser";

type BrowserRequestGuardOptions = {
  allowedOrigins?: string[];
};

declare global {
  interface Window {
    __publicPagesMswWorker?: ReturnType<typeof setupWorker>;
  }
}

function toOrigin(url: string) {
  return new URL(url).origin;
}

export async function startBrowserRequestGuard(
  options: BrowserRequestGuardOptions = {},
) {
  if (window.__publicPagesMswWorker) {
    return;
  }

  const worker = setupWorker();
  const allowedOrigins = new Set([
    window.location.origin,
    ...(options.allowedOrigins ?? []),
  ]);

  await worker.start({
    quiet: true,
    onUnhandledRequest({ method, url }) {
      const requestOrigin = toOrigin(url);
      if (allowedOrigins.has(requestOrigin)) {
        return;
      }

      throw new Error(
        `[MSW] Blocked external browser request: ${method} ${url}\n All requests to external APIs must flow through server functions`,
      );
    },
  });

  window.__publicPagesMswWorker = worker;
}
