import { redirect } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { isBypassAuth } from "./auth";

const getAuthSessionState = createServerFn({ method: "GET" }).handler(
  async () => {
    const { readAuthenticatedAccessToken } = await import(
      "../../server/auth-session"
    );

    return {
      isAuthenticated: Boolean(await readAuthenticatedAccessToken()),
    };
  },
);

export async function requireAuth() {
  if (isBypassAuth()) {
    return;
  }

  const { isAuthenticated } = await getAuthSessionState();

  if (!isAuthenticated) {
    throw redirect({
      to: "/login",
    });
  }
}

export async function redirectIfAuthenticated() {
  if (isBypassAuth()) {
    return;
  }

  const { isAuthenticated } = await getAuthSessionState();

  if (isAuthenticated) {
    throw redirect({
      to: "/",
    });
  }
}

