import {
  AUTH_SESSION_REFRESH_BUFFER_MS,
  calculateExpiresAt,
  hasActiveAuthSession,
  isAuthSessionWithinRefreshBuffer,
} from "@/routes/_login/auth.ts";
import type { AuthSessionData } from "../types/auth";
import { getServerAuthConfig } from "./env.server";
import { getAuthSession } from "./session";

type TokenRefreshResponse = {
  access_token: string;
  expires_in: number;
  id_token: string;
  refresh_token?: string;
};

type AuthSessionOptions = {
  now?: number;
  refreshBufferMs?: number;
};

export async function readCurrentAuthSession() {
  const authSession = await getAuthSession();
  return authSession.data;
}

export async function updateCurrentAuthSession(sessionData: AuthSessionData) {
  const authSession = await getAuthSession();
  await authSession.update(sessionData);
}

export async function clearCurrentAuthSession() {
  const authSession = await getAuthSession();
  await authSession.clear();
}

export async function refreshTokensWithRefreshToken(
  refreshToken: string,
  now = Date.now(),
) {
  const config = getServerAuthConfig();
  // todo: we should connect to cognito like the auth app does using the aws-sdk
  //   but again, wait until it works to do this
  const response = await fetch(config.cognitoTokenEndpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
    },
    body: new URLSearchParams({
      client_id: config.clientId,
      grant_type: "refresh_token",
      refresh_token: refreshToken,
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Token refresh failed: ${errorText}`);
  }

  const data: TokenRefreshResponse = await response.json();

  return {
    accessToken: data.access_token,
    expiresAt: calculateExpiresAt(data.expires_in, now),
    idToken: data.id_token,
    refreshToken: data.refresh_token ?? refreshToken,
  } satisfies AuthSessionData;
}

export async function readAuthenticatedAuthSession({
  now = Date.now(),
  refreshBufferMs = AUTH_SESSION_REFRESH_BUFFER_MS,
}: AuthSessionOptions = {}): Promise<AuthSessionData | null> {
  const session = await readCurrentAuthSession();

  if (!hasActiveAuthSession(session, now)) {
    if (!session.refreshToken) {
      return null;
    }
  } else if (!isAuthSessionWithinRefreshBuffer(session, now, refreshBufferMs)) {
    return session;
  }

  if (!session.refreshToken) {
    await clearCurrentAuthSession();
    return null;
  }

  try {
    const refreshedSession = await refreshTokensWithRefreshToken(
      session.refreshToken,
      now,
    );

    await updateCurrentAuthSession(refreshedSession);
    return refreshedSession;
  } catch {
    await clearCurrentAuthSession();
    return null;
  }
}

export async function readAuthenticatedAccessToken(
  options?: AuthSessionOptions,
) {
  const session = await readAuthenticatedAuthSession(options);
  return session?.accessToken ?? null;
}

