import { getRequestHeaders } from "@tanstack/start-server-core";
import { type SetupServerApi, setupServer } from "msw/node";
import { createHandler } from "request-mocking-protocol/msw";

let mswServer: SetupServerApi | null = null;

export function setupRequestMocking(): SetupServerApi {
  console.log("[RMP] setupRequestMocking() called");
  if (mswServer) {
    console.log("[RMP] reusing existing mswServer");
    return mswServer;
  }

  const mockHandler = createHandler(() => {
    // Read and return headers of the incoming HTTP request for every render.
    try {
      const headers = getRequestHeaders();
      const mockHeader = headers.get("x-mock-request");
      console.log("[RMP] getRequestHeaders() called, x-mock-request:", mockHeader ? "present" : "MISSING");
      return headers;
    } catch (e) {
      console.log("[RMP] getRequestHeaders() threw:", e);
      return null;
    }
  });

  // Type mismatch stems from MSW's split type declarations (core vs node). Safe to cast.
  mswServer = setupServer(
    // we have to cast this because of how the lib exports commonjs vs esm and
    // only the __type property is incompatible
    mockHandler as unknown as Parameters<typeof setupServer>[0],
  );
  mswServer.listen({
    onUnhandledRequest(request) {
      console.log(
        `[MSW] Unhandled request: ${request.method} ${request.url}`,
      );
    },
  });
  console.log("[RMP] mswServer.listen() called");
  return mswServer;
}

