    path: string,
    {
      body,
      method = "GET",
    }: {
      body?: unknown;
      method?: "GET" | "POST";
    } = {},
  ): Promise<T> => {
    const accessToken = await resolveOrgApiAccessToken();
    if (!accessToken) {
      throw new OrgApiError("Filed to resolve access token", 401);
    }
    const hasBody = body !== undefined;

    const apiUrl = new URL(path, getServerOrgApiBaseUrl());
    console.log("[API] fetch called:", apiUrl.toString(), "fetch is patched by MSW?", fetch.toString().includes("msw") || fetch !== globalThis.fetch);
    const response = await fetch(apiUrl, {
      body: hasBody ? JSON.stringify(body) : undefined,
      headers: {
        Accept: "application/json",
        Authorization: `Bearer ${accessToken}`,
        ...(hasBody ? { "Content-Type": "application/json" } : {}),
        "X-APP": "anedot:3",
        "X-Api-Version": "1",
        "X-Requested-With": "XMLHttpRequest",
      },
      method,
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new OrgApiError(
        errorText || `Request failed for ${path}`,
        response.status,
      );
    }

    return response.json() as Promise<T>;
  },
);

export const getOrgApiJson = createServerOnlyFn(
  async <T>(path: string): Promise<T> => {
    return requestOrgApiJson(path);
  },
);

export const postOrgApiJson = createServerOnlyFn(
  async <T>(path: string, body: unknown): Promise<T> => {
    return requestOrgApiJson(path, { body, method: "POST" });
  },
);

